object ConfigXmlParser {

  private def createSecureSAXParser(): SAXParserFactory = {
    val factory = SAXParserFactory.newInstance()
    factory.setNamespaceAware(false)
    factory.setValidating(false)
    factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
    factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
    factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
    factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true)
    factory
  }

  def parseXmlSecure(xmlString: String): Try[Elem] = {
    Try {
      val factory = createSecureSAXParser()
      val parser = factory.newSAXParser()
      val source = new InputSource(new StringReader(xmlString))
      XML.withSAXParser(parser).load(source)
    }
  }

  def parseXmlWithEntities(xmlString: String): Try[Elem] = {
    Try {
      XML.loadString(xmlString)
    }
  }

  def extractSettings(root: Elem): List[ConfigSetting] = {
    val topLevelSettings = extractSettingsFromNode(root, None)
    val sectionSettings = (root \ "section").flatMap { section =>
      val sectionName = (section \ "@name").text
      extractSettingsFromNode(section, Some(sectionName))
    }.toList
    topLevelSettings ++ sectionSettings
  }

  private def extractSettingsFromNode(node: Node, section: Option[String]): List[ConfigSetting] = {
    (node \ "setting").map { setting =>
      val key = (setting \ "@key").text match {
        case "" => (setting \ "@name").text
        case k => k
      }
      val value = (setting \ "@value").text match {
        case "" => setting.text.trim
        case v => v
      }
      ConfigSetting(key, value, section)
    }.toList
  }

  def extractSections(root: Elem): List[String] = {
    (root \ "section").map(s => (s \ "@name").text).filter(_.nonEmpty).toList
  }

  def extractSettingsAsMap(root: Elem): Map[String, String] = {
    extractSettings(root).map { s =>
      val fullKey = s.section.map(sec => s"$sec.${s.key}").getOrElse(s.key)
      fullKey -> s.value
    }.toMap
  }

  def validateXml(xmlString: String): ValidationResponse = {
    val errors = scala.collection.mutable.ListBuffer[String]()

    parseXmlSecure(xmlString) match {
      case Failure(e) =>
        errors += s"XML parsing error: ${e.getMessage}"
      case Success(root) =>
        if (root.label != "configuration" && root.label != "config") {
          errors += s"Root element should be 'configuration' or 'config', found '${root.label}'"
        }
        val settings = extractSettings(root)
        val emptyKeys = settings.filter(_.key.isEmpty)
        if (emptyKeys.nonEmpty) {
          errors += s"Found ${emptyKeys.size} setting(s) without a key"
        }
        val duplicateKeys = settings.groupBy(s => s.section.getOrElse("") + "." + s.key)
          .filter(_._2.size > 1).keys.toList
        if (duplicateKeys.nonEmpty) {
          errors += s"Duplicate keys found: ${duplicateKeys.mkString(", ")}"
        }
    }

    ValidationResponse(errors.isEmpty, errors.toList)
  }
}

object ConfigurationManagementService extends App {

