                ParseResponse(
                  success = true,
                  config = Some(ParsedConfig(settings, sections, root.toString())),
                  error = None
                )
              case Failure(ex) =>
                ParseResponse(
                  success = false,
                  config = None,
                  error = Some(s"Failed to parse XML: ${ex.getMessage}")
