                val settingsMap = ConfigXmlParser.extractSettingsAsMap(root)
                complete(settingsMap.toJson)
              case Failure(ex) =>
                complete(StatusCodes.BadRequest, Map("error" -> ex.getMessage).toJson)
            }
            result
          }
        }
      },
      path("setting" / Segment) { key =>
        post {
          entity(as[ParseRequest]) { request =>
            val result = ConfigXmlParser.parseXmlSecure(request.xml) match {
